import { useEffect, useMemo, useState } from "react";
import { Link } from "react-router-dom";

/* ------------------ COLORS ------------------ */
const severityColor = (s) => {
  if (s === "P0") return "#d32f2f"; // 🔴
  if (s === "P1") return "#f57c00"; // 🟠
  if (s === "P2") return "#fbc02d"; // 🟡
  if (s === "P3") return "#388e3c"; // 🟢
  return "#777";
};

const statusBadge = (status) => ({
  padding: "4px 10px",
  borderRadius: "12px",
  fontSize: "12px",
  background: status === "OPEN" ? "#e3f2fd" : "#e8f5e9",
  color: status === "OPEN" ? "#1976d2" : "#2e7d32",
});

/* ------------------ COMPONENT ------------------ */
export default function Dashboard() {
  const [data, setData] = useState([]);
  const [search, setSearch] = useState("");
  const [priority, setPriority] = useState("ALL");
  const [status, setStatus] = useState("ALL");

  // fetch + auto refresh
  const fetchData = async () => {
    try {
      const res = await fetch("http://localhost:8000/incidents");
      const json = await res.json();
      setData(Array.isArray(json) ? json : []);
    } catch {
      // keep simple (no layout change)
    }
  };

  useEffect(() => {
    fetchData();
    const t = setInterval(fetchData, 3000);
    return () => clearInterval(t);
  }, []);

  // filters (same behavior)
  const filtered = useMemo(() => {
    return data.filter((i) => {
      return (
        (search === "" ||
          (i.component_id || "")
            .toLowerCase()
            .includes(search.toLowerCase())) &&
        (priority === "ALL" || i.severity === priority) &&
        (status === "ALL" || i.status === status)
      );
    });
  }, [data, search, priority, status]);

  // stats
  const total = data.length;
  const open = data.filter((i) => i.status === "OPEN").length;
  const closed = data.filter((i) => i.status === "CLOSED").length;

  return (
    <div style={page}>
      {/* HEADER */}
      <div style={header}>
        <h2 style={{ margin: 0 }}>IT Incident Dashboard</h2>
      </div>

      {/* STATS */}
      <div style={stats}>
        <KPI title="Total" value={total} />
        <KPI title="Open" value={open} color="#d32f2f" />
        <KPI title="Closed" value={closed} color="#388e3c" />
      </div>

      {/* FILTERS */}
      <div style={filters}>
        <input
          placeholder="Search component..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          style={input}
        />

        <select
          value={priority}
          onChange={(e) => setPriority(e.target.value)}
          style={select}
        >
          <option value="ALL">All Priorities</option>
          <option value="P0">P0</option>
          <option value="P1">P1</option>
          <option value="P2">P2</option>
          <option value="P3">P3</option>
        </select>

        <select
          value={status}
          onChange={(e) => setStatus(e.target.value)}
          style={select}
        >
          <option value="ALL">All Status</option>
          <option value="OPEN">OPEN</option>
          <option value="CLOSED">CLOSED</option>
        </select>
      </div>

      {/* GRID */}
      <div style={grid}>
        {filtered.map((i) => (
          <div
            key={i.id}
            style={card}
            onMouseEnter={(e) => {
              e.currentTarget.style.transform = "translateY(-3px)";
              e.currentTarget.style.boxShadow =
                "0 6px 16px rgba(0,0,0,0.12)";
            }}
            onMouseLeave={(e) => {
              e.currentTarget.style.transform = "none";
              e.currentTarget.style.boxShadow =
                "0 4px 12px rgba(0,0,0,0.08)";
            }}
          >
            <div style={cardHeader}>
              <h3 style={{ margin: 0 }}>{i.component_id}</h3>
              <span style={statusBadge(i.status)}>{i.status}</span>
            </div>

            <p style={sub}>Incident #{i.id}</p>

            <div style={row}>
              <span
                style={{
                  ...badge,
                  background: severityColor(i.severity),
                }}
              >
                {i.severity}
              </span>

              <span style={signal}>Signals: {i.signal_count ?? 0}</span>
            </div>

            <p style={time}>
              {i.start_time
                ? new Date(i.start_time).toLocaleString()
                : "-"}
            </p>

            <Link to={`/incident/${i.id}`} style={linkBtn}>
              View Details →
            </Link>
          </div>
        ))}
      </div>
    </div>
  );
}

/* ------------------ SMALL COMPONENT ------------------ */
function KPI({ title, value, color = "#333" }) {
  return (
    <div style={kpi}>
      <p style={{ margin: 0, color: "#666" }}>{title}</p>
      <h2 style={{ margin: 0, color }}>{value}</h2>
    </div>
  );
}

/* ------------------ STYLES (polished only) ------------------ */
const page = {
  background: "#f5f7fa",
  minHeight: "100vh",
  padding: "25px",
  fontFamily: "Segoe UI",
};

const header = {
  marginBottom: "15px",
};

const stats = {
  display: "flex",
  gap: "15px",
  marginBottom: "20px",
};

const kpi = {
  background: "#fff",
  padding: "12px 16px",
  borderRadius: "12px",
  boxShadow: "0 2px 8px rgba(0,0,0,0.06)",
  minWidth: "120px",
};

const filters = {
  display: "flex",
  gap: "10px",
  marginBottom: "20px",
};

const input = {
  padding: "8px",
  borderRadius: "8px",
  border: "1px solid #ccc",
};

const select = {
  padding: "8px",
  borderRadius: "8px",
  border: "1px solid #ccc",
  background: "#fff",
  color: "#000",
};

const grid = {
  display: "grid",
  gridTemplateColumns: "repeat(auto-fit, minmax(260px, 1fr))",
  gap: "20px",
};

const card = {
  background: "#fff",
  padding: "18px",
  borderRadius: "12px",
  boxShadow: "0 4px 12px rgba(0,0,0,0.08)",
  transition: "0.2s ease",
};

const cardHeader = {
  display: "flex",
  justifyContent: "space-between",
  alignItems: "center",
};

const sub = {
  color: "#666",
  marginTop: "6px",
};

const row = {
  display: "flex",
  justifyContent: "space-between",
  marginTop: "10px",
};

const badge = {
  padding: "4px 10px",
  borderRadius: "8px",
  color: "#fff",
  fontSize: "12px",
};

const signal = {
  fontSize: "12px",
  color: "#555",
};

const time = {
  fontSize: "12px",
  color: "#888",
  marginTop: "8px",
};

const linkBtn = {
  display: "inline-block",
  marginTop: "10px",
  padding: "6px 10px",
  background: "#2f6fed",
  color: "#fff",
  borderRadius: "6px",
  textDecoration: "none",
};
